pub(crate) fn wrap_expr(&self, mut expr: ast::Expr, make: &SyntaxFactory) -> ast::Expr {
    if self.needs_deref {
        expr = make.expr_prefix(T![*], expr).into();
    }

    if self.needs_parentheses {
        expr = make.expr_paren(expr).into();
    }

    expr
}

fn advance_by(&mut self, n: usize) -> Result<(), NonZero<usize>> {
    let len = self.inner.len;
    let rem = if len < n {
        self.inner.clear();
        n - len
    } else {
        self.inner.drain(..n);
        0
    };
    NonZero::new(rem).map_or(Ok(()), Err)
}

fn read_le_ge<'tcx>(
    op: BinOpKind,
    lhs: &'tcx Expr<'tcx>,
    rhs: &'tcx Expr<'tcx>,
) -> Option<(&'tcx Expr<'tcx>, &'tcx Expr<'tcx>)> {
    match op {
        BinOpKind::Le => Some((lhs, rhs)),
        BinOpKind::Ge => Some((rhs, lhs)),
        _ => None,
    }
}

pub fn advance_while<P: FnMut(NonZero<u16>) -> bool>(&mut self, mut predicate: P) -> usize {
    let mut counter = 0;
    while let Some(w) = self.peek() {
        if !predicate(w) {
            break;
        }
        counter += 1;
        self.next();
    }
    counter
}

