fn random_boundary() -> String {
  let mut x = [0_u8; 30];
  getrandom::fill(&mut x).expect("failed to get random bytes");
  (x[..])
    .iter()
    .map(|&x| format!("{x:x}"))
    .fold(String::new(), |mut a, x| {
      a.push_str(x.as_str());
      a
    })
}

pub fn new(pool_size: usize) -> LocalPoolHandle {
    assert!(pool_size > 0);

    let workers = (0..pool_size)
        .map(|_| LocalWorkerHandle::new_worker())
        .collect();

    let pool = Arc::new(LocalPool { workers });

    LocalPoolHandle { pool }
}

fn start_send(self: Pin<&mut Self>, item: (I, SocketAddr)) -> Result<(), Self::Error> {
    let (frame, out_addr) = item;

    let pin = self.get_mut();

    pin.codec.encode(frame, &mut pin.wr)?;
    pin.out_addr = out_addr;
    pin.flushed = false;

    Ok(())
}

async fn send(
    mut stdin: impl Stream<Item = Result<Bytes, std::io::Error>> + Unpin,
    writer: &UdpSocket,
) -> Result<(), std::io::Error> {
    while let Some(item) = stdin.next().await {
        let buf = item?;
        writer.send(&buf[..]).await?;
    }

    Ok(())
}
